/**
 * AI Module Types
 *
 * Type definitions for future AI module implementation.
 * This file defines interfaces for AI-powered content generation,
 * suggestions, and intelligent analysis features.
 *
 * @module modules/_stubs/ai/types
 *
 * @example
 * ```typescript
 * import type {
 *   IAIService,
 *   ContentGenerationRequest,
 *   AISuggestion,
 * } from '@/modules/_stubs/ai';
 * ```
 */

// -----------------------------------------------------------------------------
// Enums
// -----------------------------------------------------------------------------

/**
 * AI feature type
 */
export enum AIFeatureType {
  /** Content generation */
  CONTENT_GENERATION = 'CONTENT_GENERATION',
  /** Image analysis */
  IMAGE_ANALYSIS = 'IMAGE_ANALYSIS',
  /** Translation */
  TRANSLATION = 'TRANSLATION',
  /** Suggestion */
  SUGGESTION = 'SUGGESTION',
  /** Forecasting */
  FORECASTING = 'FORECASTING',
}

/**
 * Content type for generation
 */
export enum ContentType {
  /** Menu item description */
  ITEM_DESCRIPTION = 'ITEM_DESCRIPTION',
  /** Category description */
  CATEGORY_DESCRIPTION = 'CATEGORY_DESCRIPTION',
  /** Menu introduction */
  MENU_INTRO = 'MENU_INTRO',
  /** Marketing copy */
  MARKETING_COPY = 'MARKETING_COPY',
  /** Social media post */
  SOCIAL_POST = 'SOCIAL_POST',
}

/**
 * Suggestion type
 */
export enum SuggestionType {
  /** Price adjustment suggestion */
  PRICE_ADJUSTMENT = 'PRICE_ADJUSTMENT',
  /** Menu optimization */
  MENU_OPTIMIZATION = 'MENU_OPTIMIZATION',
  /** Inventory alert */
  INVENTORY_ALERT = 'INVENTORY_ALERT',
  /** Peak hour staffing */
  STAFFING = 'STAFFING',
  /** Promotion idea */
  PROMOTION = 'PROMOTION',
}

/**
 * Language code
 */
export enum LanguageCode {
  TR = 'tr',
  EN = 'en',
  DE = 'de',
  FR = 'fr',
  AR = 'ar',
  RU = 'ru',
}

// -----------------------------------------------------------------------------
// Content Generation Types
// -----------------------------------------------------------------------------

/**
 * Content generation context
 */
export interface GenerationContext {
  /** Item name */
  name: string;
  /** Category */
  category?: string;
  /** Keywords */
  keywords?: string[];
  /** Ingredients */
  ingredients?: string[];
  /** Price */
  price?: number;
  /** Target audience */
  targetAudience?: string;
  /** Tone (formal, casual, fun) */
  tone?: 'formal' | 'casual' | 'fun' | 'luxury';
  /** Max length */
  maxLength?: number;
  /** Language */
  language?: LanguageCode;
}

/**
 * Generated content
 */
export interface GeneratedContent {
  /** Generated text */
  text: string;
  /** Alternative versions */
  alternatives?: string[];
  /** Confidence score */
  confidence: number;
  /** Tokens used */
  tokensUsed: number;
  /** Language */
  language: LanguageCode;
  /** Generation time in ms */
  generationTime: number;
}

/**
 * Content generation request
 */
export interface ContentGenerationRequest {
  /** Content type */
  type: ContentType;
  /** Generation context */
  context: GenerationContext;
  /** Number of alternatives */
  alternatives?: number;
}

// -----------------------------------------------------------------------------
// Image Analysis Types
// -----------------------------------------------------------------------------

/**
 * Image analysis request
 */
export interface ImageAnalysisRequest {
  /** Image URL or base64 */
  image: string;
  /** Analysis features */
  features: Array<'ingredients' | 'allergens' | 'cuisine' | 'quality' | 'description'>;
}

/**
 * Image analysis result
 */
export interface ImageAnalysisResult {
  /** Detected ingredients */
  ingredients?: string[];
  /** Detected allergens */
  allergens?: string[];
  /** Cuisine type */
  cuisine?: string;
  /** Quality score (1-10) */
  qualityScore?: number;
  /** Auto-generated description */
  description?: string;
  /** Confidence scores */
  confidence: Record<string, number>;
}

// -----------------------------------------------------------------------------
// Translation Types
// -----------------------------------------------------------------------------

/**
 * Translation request
 */
export interface TranslationRequest {
  /** Text to translate */
  text: string;
  /** Source language */
  sourceLanguage: LanguageCode;
  /** Target languages */
  targetLanguages: LanguageCode[];
  /** Context (for better translation) */
  context?: string;
}

/**
 * Translation result
 */
export interface TranslationResult {
  /** Original text */
  original: string;
  /** Translations by language */
  translations: Record<LanguageCode, string>;
  /** Confidence scores */
  confidence: Record<LanguageCode, number>;
}

// -----------------------------------------------------------------------------
// Suggestion Types
// -----------------------------------------------------------------------------

/**
 * AI suggestion
 */
export interface AISuggestion {
  /** Suggestion ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Suggestion type */
  type: SuggestionType;
  /** Title */
  title: string;
  /** Description */
  description: string;
  /** Suggested action */
  action: string;
  /** Related entity ID */
  entityId?: string;
  /** Related entity type */
  entityType?: string;
  /** Confidence score */
  confidence: number;
  /** Priority (1-10) */
  priority: number;
  /** Potential impact */
  potentialImpact?: string;
  /** Is dismissed */
  isDismissed: boolean;
  /** Created at */
  createdAt: Date;
  /** Expires at */
  expiresAt?: Date;
}

/**
 * Demand forecast
 */
export interface DemandForecast {
  /** Forecast ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Item ID (if item-specific) */
  itemId?: string;
  /** Date */
  date: Date;
  /** Predicted orders */
  predictedOrders: number;
  /** Confidence interval */
  confidenceInterval: {
    low: number;
    high: number;
  };
  /** Factors */
  factors: Array<{
    name: string;
    impact: number;
  }>;
}

// -----------------------------------------------------------------------------
// Service Interfaces
// -----------------------------------------------------------------------------

/**
 * AI service interface
 */
export interface IAIService {
  /**
   * Generate content
   */
  generateContent(
    organizationId: string,
    request: ContentGenerationRequest
  ): Promise<GeneratedContent>;

  /**
   * Analyze image
   */
  analyzeImage(
    organizationId: string,
    request: ImageAnalysisRequest
  ): Promise<ImageAnalysisResult>;

  /**
   * Translate text
   */
  translate(
    organizationId: string,
    request: TranslationRequest
  ): Promise<TranslationResult>;

  /**
   * Get suggestions
   */
  getSuggestions(
    organizationId: string,
    type?: SuggestionType
  ): Promise<AISuggestion[]>;

  /**
   * Dismiss suggestion
   */
  dismissSuggestion(
    organizationId: string,
    suggestionId: string
  ): Promise<void>;

  /**
   * Get demand forecast
   */
  getDemandForecast(
    organizationId: string,
    dateRange: { start: Date; end: Date },
    itemId?: string
  ): Promise<DemandForecast[]>;
}

/**
 * Content generator service interface
 */
export interface IContentGeneratorService {
  /**
   * Generate item description
   */
  generateItemDescription(
    itemName: string,
    context: GenerationContext
  ): Promise<string>;

  /**
   * Generate category description
   */
  generateCategoryDescription(
    categoryName: string,
    items: string[],
    context: Partial<GenerationContext>
  ): Promise<string>;

  /**
   * Generate menu introduction
   */
  generateMenuIntro(
    restaurantName: string,
    cuisine: string,
    context: Partial<GenerationContext>
  ): Promise<string>;

  /**
   * Generate marketing copy
   */
  generateMarketingCopy(
    subject: string,
    purpose: string,
    context: Partial<GenerationContext>
  ): Promise<string>;
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Content generated event payload
 */
export interface ContentGeneratedEventPayload {
  organizationId: string;
  contentType: ContentType;
  entityId?: string;
  tokensUsed: number;
  timestamp: string;
}

/**
 * Suggestion created event payload
 */
export interface SuggestionCreatedEventPayload {
  organizationId: string;
  suggestionId: string;
  suggestionType: SuggestionType;
  priority: number;
  timestamp: string;
}

/**
 * Analysis completed event payload
 */
export interface AnalysisCompletedEventPayload {
  organizationId: string;
  analysisType: AIFeatureType;
  entityId?: string;
  success: boolean;
  timestamp: string;
}
